inline bool VerifyUpdateType(flatbuffers::Verifier &verifier, const void *obj, UpdateType type) {
  switch (type) {
    case UpdateType::NONE: {
      return true;
    }
    case UpdateType::RepoInitializedUpdate: {
      auto ptr = reinterpret_cast<const generated::RepoInitializedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::RepoMigratedUpdate: {
      auto ptr = reinterpret_cast<const generated::RepoMigratedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::ConfigChangedUpdate: {
      auto ptr = reinterpret_cast<const generated::ConfigChangedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::MetadataChangedUpdate: {
      auto ptr = reinterpret_cast<const generated::MetadataChangedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::TagCreatedUpdate: {
      auto ptr = reinterpret_cast<const generated::TagCreatedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::TagDeletedUpdate: {
      auto ptr = reinterpret_cast<const generated::TagDeletedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::BranchCreatedUpdate: {
      auto ptr = reinterpret_cast<const generated::BranchCreatedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::BranchDeletedUpdate: {
      auto ptr = reinterpret_cast<const generated::BranchDeletedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::BranchResetUpdate: {
      auto ptr = reinterpret_cast<const generated::BranchResetUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::NewCommitUpdate: {
      auto ptr = reinterpret_cast<const generated::NewCommitUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::CommitAmendedUpdate: {
      auto ptr = reinterpret_cast<const generated::CommitAmendedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::NewDetachedSnapshotUpdate: {
      auto ptr = reinterpret_cast<const generated::NewDetachedSnapshotUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::GCRanUpdate: {
      auto ptr = reinterpret_cast<const generated::GCRanUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::ExpirationRanUpdate: {
      auto ptr = reinterpret_cast<const generated::ExpirationRanUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::FeatureFlagChangedUpdate: {
      auto ptr = reinterpret_cast<const generated::FeatureFlagChangedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case UpdateType::RepoStatusChangedUpdate: {
      auto ptr = reinterpret_cast<const generated::RepoStatusChangedUpdate *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyUpdateTypeVector(flatbuffers::Verifier &verifier, const flatbuffers::Vector<flatbuffers::Offset<void>> *values, const flatbuffers::Vector<UpdateType> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyUpdateType(
        verifier,  values->Get(i), types->GetEnum<UpdateType>(i))) {
      return false;
    }
  }
  return true;
}

